private static IEnumerable<CountResult> ReadFacets(ISearchResponse<SparePartEntity> queryResponse)
{
    var filterTypes = Enum.GetValues(typeof(FilterType)).Cast<FilterType>();
    var result = filterTypes
        .Where(v => queryResponse.Aggregations != null && queryResponse.Aggregations.ContainsKey(v.ToString()))
        .Select(value => new { value, termAggregation = queryResponse.Aggregations[value.ToString()] as TermsAggregation })
        .Select(aggregation => new CountResult()
        {
            FilterType = aggregation.value,
            Name = aggregation.value.ToString(),
            FilterCounts = aggregation.termAggregation.Buckets.Select(s =>
                new FilterCount()
                {
                    Count = (int)s.DocCount,
                    Id = s.Key
                }).ToList()
        });
    return result;
}

private static SearchDescriptor<SparePartEntity> AddAggregationsFromAttributeId(SearchDescriptor<SparePartEntity> searchDescriptor, SearchRequest request)
{
    if (!request.ReturnFacets)
    {
        return searchDescriptor;
    }

    var aggregations = new AggregationContainerDescriptor<SparePartEntity>();

    foreach (var filterType in Enum.GetValues(typeof(FilterType)).Cast<FilterType>())
    {
        aggregations.Terms(filterType.ToString(), t => t.Field(f => f.AttributeId));
    }

    searchDescriptor.Aggregations(a => aggregations);

    return searchDescriptor;
}

